// C: #define ispseudo(i)  ((i) <= LUA_REGISTRYINDEX)
#[inline]
fn is_pseudo(idx: i32) -> bool {
    idx <= LUA_REGISTRYINDEX
}

// C: #define isupvalue(i)  ((i) < LUA_REGISTRYINDEX)
#[inline]
fn is_upvalue(idx: i32) -> bool {
    idx < LUA_REGISTRYINDEX
}

