    pub nilvalue: LuaValue,

    // C: unsigned int seed — randomized seed for hashes
    // types.tsv: global_State.seed → u32
    pub seed: u32,

    // C: lu_byte currentwhite — Phase D GC color
    // types.tsv: global_State.currentwhite → u8
    pub currentwhite: u8,

