/// ```c
/// // C: LUA_API int lua_setcstacklimit(lua_State *L, unsigned int limit) {
/// //   UNUSED(L); UNUSED(limit);
/// //   return LUAI_MAXCCALLS;  /* warning?? */
/// // }
